## Pseudocode — serialize_v3_live_first

```rust
pub(crate) fn serialize_v3_live_first(store: &Store) -> Result<Vec<u8>, FerraError> {
    // Build PositionalStore to get canonical order + live_bits
    let positional = PositionalStore::from_datoms(store.datoms().cloned());

    // Partition datoms by live_bits
    let mut live_datoms = Vec::new();
    let mut hist_datoms = Vec::new();
    for (i, datom) in positional.datoms().iter().enumerate() {
        let pos = u32::try_from(i).unwrap_or(u32::MAX);
        if positional.is_live(pos) {
            live_datoms.push(datom.clone());
        } else {
            hist_datoms.push(datom.clone());
        }
    }
    // Both partitions are EAVT-sorted (subsequences of canonical order)

    let mut schema_pairs: Vec<(String, AttributeDef)> = store.schema().iter()
        .map(|(a, d)| (a.as_str().to_owned(), d.clone())).collect();
    schema_pairs.sort_by(|(a, _), (b, _)| a.cmp(b)); // deterministic

    let payload = V3LiveFirstPayloadWrite { schema_pairs, live_datoms, hist_datoms };

    let mut buf = Vec::new();
    buf.extend_from_slice(&V3_MAGIC);
    buf.extend_from_slice(&V3_LIVE_FIRST_VERSION.to_le_bytes());
    buf.extend_from_slice(&store.epoch().to_le_bytes());
    buf.extend_from_slice(store.genesis_agent().as_bytes());

    let payload_bytes = bincode::serialize(&payload)
        .map_err(|e| FerraError::CheckpointWrite(e.to_string()))?;
    buf.extend_from_slice(&payload_bytes);

    let hash = blake3::hash(&buf);
    buf.extend_from_slice(hash.as_bytes());
    Ok(buf)
}
```

