```rust
/// LIVE-only store with retained historical datoms for lazy merge.
pub(crate) struct PartialStore {
    /// Store built from LIVE datoms only.
    store: Store,
    /// Historical datoms (already trusted — BLAKE3 verified at load).
    /// Retained for load_historical() merge.
    hist_datoms: Vec<Datom>,
    /// Schema pairs for rebuild during load_historical.
    schema_pairs: Vec<(String, AttributeDef)>,
    /// Epoch from checkpoint.
    epoch: u64,
    /// Genesis agent from checkpoint.
    genesis_agent: AgentId,
}

impl PartialStore {
    pub(crate) fn store(&self) -> &Store { &self.store }

    /// Merge LIVE + HISTORICAL datoms into complete Store. O(n) merge-sort.
    pub(crate) fn load_historical(self) -> Store {
        let live_datoms: Vec<Datom> = self.store.datoms().cloned().collect();
        // merge_sort_dedup: O(n+m) on two EAVT-sorted slices
        let merged = crate::positional::merge_sort_dedup_pub(&live_datoms, &self.hist_datoms);
        Store::from_checkpoint(self.epoch, self.genesis_agent, self.schema_pairs, merged)
    }
}

pub(crate) fn cold_start_live_first(data: &[u8]) -> Result<PartialStore, FerraError> {
    // BLAKE3 verify (same as standard V3)
    if data.len() < V3_HEADER_SIZE + HASH_SIZE {
        return Err(FerraError::CheckpointCorrupted { expected: "V3 min size".into(), actual: format!("{} bytes", data.len()) });
    }
    let (content, hash_bytes) = data.split_at(data.len() - HASH_SIZE);
    let computed = blake3::hash(content);
    if computed.as_bytes() != hash_bytes {
        return Err(FerraError::CheckpointCorrupted { expected: "BLAKE3 match".into(), actual: "mismatch".into() });
    }
    // Parse header
    let epoch = u64::from_le_bytes(content[6..14].try_into().map_err(|_| FerraError::CheckpointCorrupted { expected: "epoch".into(), actual: "truncated".into() })?);
    let genesis_agent = AgentId::from_bytes(content[14..30].try_into().map_err(|_| FerraError::CheckpointCorrupted { expected: "genesis_agent".into(), actual: "truncated".into() })?);

    // Single bincode deserialize — WireDatom for ADR-FERR-010
    let payload: V3LiveFirstPayloadRead = bincode::deserialize(&content[V3_HEADER_SIZE..])
        .map_err(|e| FerraError::CheckpointCorrupted { expected: "V3 LIVE-first payload".into(), actual: e.to_string() })?;

    // Trust boundary: WireDatom → Datom
    let live_datoms: Vec<Datom> = payload.live_datoms.into_iter().map(|wd| wd.into_trusted()).collect();
    let hist_datoms: Vec<Datom> = payload.hist_datoms.into_iter().map(|wd| wd.into_trusted()).collect();

    // Build LIVE-only Store
    let store = Store::from_checkpoint(epoch, genesis_agent, payload.schema_pairs.clone(), live_datoms);

    Ok(PartialStore { store, hist_datoms, schema_pairs: payload.schema_pairs, epoch, genesis_agent })
}
```

