## Pseudocode — interpolation_search (NEW helper in positional.rs, ~20 lines)

```rust
/// Interpolation search on EAVT-sorted canonical array (INV-FERR-027).
/// O(log log n) expected for uniformly distributed EntityId (BLAKE3).
fn interpolation_search(canonical: &[Datom], key: &EavtKey) -> Option<&Datom> {
    if canonical.is_empty() { return None; }
    let mut lo: usize = 0;
    let mut hi: usize = canonical.len() - 1;

    while lo <= hi {
        // Extract first 8 bytes of EntityId as u64 for interpolation
        let lo_val = entity_u64(&canonical[lo]);
        let hi_val = entity_u64(&canonical[hi]);
        let key_val = entity_key_u64(key);

        // Guard: if all entities in range are the same, fall back to midpoint
        let pos = if hi_val == lo_val {
            lo + (hi - lo) / 2 // standard binary search midpoint
        } else {
            // Interpolation estimate: pos = lo + (key - lo_val) / (hi_val - lo_val) * (hi - lo)
            // Use u128 to prevent overflow in (key_val - lo_val) * (hi - lo)
            let numerator = (key_val.saturating_sub(lo_val) as u128) * ((hi - lo) as u128);
            let denominator = (hi_val - lo_val) as u128;
            let estimate = lo + (numerator / denominator) as usize;
            estimate.clamp(lo, hi) // safety: keep within bounds
        };

        match EavtKey::from_datom(&canonical[pos]).cmp(key) {
            std::cmp::Ordering::Equal => return Some(&canonical[pos]),
            std::cmp::Ordering::Less => lo = pos + 1,
            std::cmp::Ordering::Greater => {
                if pos == 0 { return None; } // prevent underflow
                hi = pos - 1;
            }
        }
    }
    None
}

/// Extract first 8 bytes of a Datom's EntityId as u64 (big-endian).
fn entity_u64(datom: &Datom) -> u64 {
    let b = datom.entity().as_bytes();
    u64::from_be_bytes([b[0], b[1], b[2], b[3], b[4], b[5], b[6], b[7]])
}

/// Extract first 8 bytes of an EavtKey's EntityId as u64 (big-endian).
fn entity_key_u64(key: &EavtKey) -> u64 {
    let b = key.0.as_bytes(); // EavtKey.0 is EntityId
    u64::from_be_bytes([b[0], b[1], b[2], b[3], b[4], b[5], b[6], b[7]])
}
```

